     1→import type { Finding, ProcessResult, ReviewResult } from "../types.js";
     2→
     3→export const REVIEW_COMMENT_HEADER = "# Vibereq Review";
     4→
     5→export const SEVERITY_EMOJI: Record<string, string> = {
     6→  critical: ":x:",
     7→  major: ":warning:",
     8→  minor: ":grey_question:",
     9→  info: ":information_source:",
    10→};
    11→
    12→export const STATUS_EMOJI: Record<string, string> = {
    13→  fulfilled: ":white_check_mark:",
    14→  partial: ":yellow_circle:",
    15→  missing: ":red_circle:",
    16→  violation: ":x:",
    17→};
    18→
    19→interface ReviewComment {
    20→  path: string;
    21→  line: number;
    22→  start_line?: number;
    23→  body: string;
    24→}
    25→
    26→async function runCommand(cmd: string[]): Promise<ProcessResult> {
    27→  const proc = Bun.spawn(cmd, { stdout: "pipe", stderr: "pipe" });
    28→  const stdout = await new Response(proc.stdout).text();
    29→  const stderr = await new Response(proc.stderr).text();
    30→  const exitCode = await proc.exited;
    31→  return { stdout, stderr, exitCode };
    32→}
    33→
    34→export async function getCurrentPR(): Promise<number | null> {
    35→  // GitHub Actions sets GITHUB_EVENT_PATH with the event payload
    36→  if (process.env.GITHUB_EVENT_NAME === "pull_request") {
    37→    const eventPath = process.env.GITHUB_EVENT_PATH;
    38→    if (eventPath) {
    39→      try {
    40→        const file = Bun.file(eventPath);
    41→        const event = await file.json();
    42→        const prNumber = event?.pull_request?.number;
    43→        if (typeof prNumber === "number") {
    44→          return prNumber;
    45→        }
    46→      } catch {
    47→        // Fall through to gh CLI
    48→      }
    49→    }
    50→  }
    51→
    52→  // Try to get PR from gh CLI
    53→  const result = await runCommand([
    54→    "gh",
    55→    "pr",
    56→    "view",
    57→    "--json",
    58→    "number",
    59→    "-q",
    60→    ".number",
    61→  ]);
    62→  if (result.exitCode === 0 && /^\d+$/.test(result.stdout.trim())) {
    63→    return parseInt(result.stdout.trim(), 10);
    64→  }
    65→
    66→  return null;
    67→}
    68→
    69→export async function getDiffLines(
    70→  baseBranch = "main"
    71→): Promise<Map<string, Set<number>>> {
    72→  const result = await runCommand([
    73→    "git",
    74→    "diff",
    75→    `${baseBranch}...HEAD`,
    76→    "--unified=0",
    77→  ]);
    78→  if (result.exitCode !== 0) {
    79→    return new Map();
    80→  }
    81→
    82→  const diffLines = new Map<string, Set<number>>();
    83→  let currentFile: string | null = null;
    84→
    85→  for (const line of result.stdout.split("\n")) {
    86→    // Match file header: +++ b/path/to/file.ts
    87→    if (line.startsWith("+++ b/")) {
    88→      currentFile = line.slice(6);
    89→      diffLines.set(currentFile, new Set());
    90→    }
    91→    // Match hunk header: @@ -old,count +new,count @@
    92→    else if (line.startsWith("@@") && currentFile) {
    93→      const match = /\+(\d+)(?:,(\d+))?/.exec(line);
    94→      if (match) {
    95→        const start = parseInt(match[1], 10);
    96→        const count = match[2] ? parseInt(match[2], 10) : 1;
    97→        const fileLines = diffLines.get(currentFile)!;
    98→        for (let i = start; i < start + count; i++) {
    99→          fileLines.add(i);
   100→        }
   101→      }
   102→    }
   103→  }
   104→
   105→  return diffLines;
   106→}
   107→
   108→function formatFindingForDiffComment(finding: Finding): string {
   109→  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
   110→  const statusEmoji = STATUS_EMOJI[finding.status] || "";
   111→
   112→  return [
   113→    `${severityEmoji} **${finding.requirement}**`,
   114→    `Status: ${statusEmoji} ${finding.status}`,
   115→    "",
   116→    finding.details,
   117→  ].join("\n");
   118→}
   119→
   120→async function getCommitSha(prNumber: number): Promise<string | null> {
   121→  const shaResult = await runCommand([
   122→    "gh",
   123→    "pr",
   124→    "view",
   125→    String(prNumber),
   126→    "--json",
   127→    "headRefOid",
   128→    "-q",
   129→    ".headRefOid",
   130→  ]);
   131→  if (shaResult.exitCode !== 0) {
   132→    console.error(`Failed to get PR head commit: ${shaResult.stderr}`);
   133→    return null;
   134→  }
   135→  return shaResult.stdout.trim();
   136→}
   137→
   138→function buildReviewComment(finding: Finding): ReviewComment | null {
   139→  if (!finding.location) return null;
   140→
   141→  const body = formatFindingForDiffComment(finding);
   142→  const comment: ReviewComment = {
   143→    path: finding.location.file,
   144→    line: finding.location.endLine ?? finding.location.line,
   145→    body,
   146→  };
   147→
   148→  if (
   149→    finding.location.endLine &&
   150→    finding.location.endLine !== finding.location.line
   151→  ) {
   152→    comment.start_line = finding.location.line;
   153→  }
   154→
   155→  return comment;
   156→}
   157→
   158→async function resolveReviewThread(threadId: string): Promise<boolean> {
   159→  const query = `
   160→    mutation ResolveThread($threadId: ID!) {
   161→      resolveReviewThread(input: {threadId: $threadId}) {
   162→        thread {
   163→          id
   164→        }
   165→      }
   166→    }
   167→  `;
   168→
   169→  const result = await runCommand([
   170→    "gh",
   171→    "api",
   172→    "graphql",
   173→    "-f",
   174→    `query=${query}`,
   175→    "-f",
   176→    `threadId=${threadId}`,
   177→  ]);
   178→
   179→  return result.exitCode === 0;
   180→}
   181→
   182→async function getReviewThreads(
   183→  prNumber: number
   184→): Promise<Array<{ id: string; path: string; line: number }>> {
   185→  const query = `
   186→    query GetReviewThreads($owner: String!, $repo: String!, $pr: Int!) {
   187→      repository(owner: $owner, name: $repo) {
   188→        pullRequest(number: $pr) {
   189→          reviewThreads(last: 100) {
   190→            nodes {
   191→              id
   192→              isResolved
   193→              path
   194→              line
   195→            }
   196→          }
   197→        }
   198→      }
   199→    }
   200→  `;
   201→
   202→  // Get owner and repo from gh
   203→  const repoResult = await runCommand([
   204→    "gh",
   205→    "repo",
   206→    "view",
   207→    "--json",
   208→    "owner,name",
   209→  ]);
   210→  if (repoResult.exitCode !== 0) return [];
   211→
   212→  const repoInfo = JSON.parse(repoResult.stdout);
   213→  const owner = repoInfo.owner.login;
   214→  const repo = repoInfo.name;
   215→
   216→  const result = await runCommand([
   217→    "gh",
   218→    "api",
   219→    "graphql",
   220→    "-f",
   221→    `query=${query}`,
   222→    "-f",
   223→    `owner=${owner}`,
   224→    "-f",
   225→    `repo=${repo}`,
   226→    "-F",
   227→    `pr=${prNumber}`,
   228→  ]);
   229→
   230→  if (result.exitCode !== 0) return [];
   231→
   232→  try {
   233→    const data = JSON.parse(result.stdout);
   234→    const threads = data.data.repository.pullRequest.reviewThreads.nodes;
   235→    return threads
   236→      .filter((t: { isResolved: boolean }) => !t.isResolved)
   237→      .map((t: { id: string; path: string; line: number }) => ({
   238→        id: t.id,
   239→        path: t.path,
   240→        line: t.line,
   241→      }));
   242→  } catch {
   243→    return [];
   244→  }
   245→}
   246→
   247→export async function submitReview(
   248→  prNumber: number,
   249→  result: ReviewResult,
   250→  diffFindings: Finding[],
   251→  generalFindings: Finding[],
   252→  dryRun = false
   253→): Promise<{ success: boolean; failedFindings: Finding[] }> {
   254→  const failedFindings: Finding[] = [];
   255→
   256→  // Build review comments from diff findings
   257→  const comments: ReviewComment[] = [];
   258→  const fulfilledComments: Array<{ path: string; line: number }> = [];
   259→
   260→  for (const finding of diffFindings) {
   261→    const comment = buildReviewComment(finding);
   262→    if (comment) {
   263→      comments.push(comment);
   264→      if (finding.status === "fulfilled") {
   265→        fulfilledComments.push({ path: comment.path, line: comment.line });
   266→      }
   267→    } else {
   268→      failedFindings.push(finding);
   269→    }
   270→  }
   271→
   272→  // Build review body from general findings and summary
   273→  const reviewBody = formatReviewBody(result, generalFindings);
   274→
   275→  if (dryRun) {
   276→    console.log(`[DRY RUN] Would submit review with ${comments.length} diff comment(s)`);
   277→    for (const comment of comments) {
